const contact = $input.first().json;

// Support both HubSpot property structure AND flat form input
const props = contact.properties || contact;

// Map flat form fields OR HubSpot properties
let website = props.WebsiteURL || props.website || props.company_website || '';
let company = props.company || props.Company || 'Unknown Company';
let email = props.Email || props.email || '';
let firstname = props.firstname || (props.Name ? props.Name.split(' ')[0] : '');
let lastname = props.lastname || (props.Name ? props.Name.split(' ').slice(1).join(' ') : '');
let growth_challenge = props['Growth challenge'] || props.growth_challenge || '';
let slideDeckId = props['Slide deck ID'] || props.slide_deck_id || '';
let phone = props['Phone number '] || props['Phone number'] || props.phone || '';
let contactId = contact.objectId || contact.vid || props.hs_object_id || email;

// Normalize website URL
if (website && !website.startsWith('http')) {
  website = 'https://' + website.replace(/^\/+/, '');
}
website = website.replace(/\/$/, '');

// Extract domain
let domain = '';
try {
  domain = new URL(website).hostname.replace('www.', '');
} catch (e) {
  domain = website.replace(/https?:\/\//, '').replace('www.', '').split('/')[0];
}

if (!website || !domain) {
  throw new Error('No website found on contact - cannot enrich');
}

return [{
  json: {
    contactId,
    email,
    fullName: `${firstname} ${lastname}`.trim(),
    company,
    website,
    domain,
    growth_challenge,
    slideDeckId,
    phone,
    timestamp: new Date().toISOString()
  }
}];

// Pak de ruwe tekst uit de LLM output
const rawText = $json.content[0].text;

// Verwijder markdown code blocks (```json ... ```) als die eromheen staan
const cleanJson = rawText.replace(/```json|```/g, "").trim();

// Zet de tekst om naar een bruikbaar object
const data = JSON.parse(cleanJson);

return {
  brand_name: data.brand_name,
  industry: data.industry,
  core_proposition: data.core_proposition,
  competitor_keywords: data.competitor_keywords
};

// Pak data uit de eerdere nodes
const marktData = $("Keyword Industry").all()[0].json.tasks[0].result[0].items;
const prospectData = $("Get ranked keywords").all()[0].json.tasks[0].result[0].items;

// 1. Maak een lijst van keywords waar de prospect nu al op rankt (top 30)
const prospectKeywords = prospectData
  .filter(item => item.ranked_serp_element.serp_item.rank_absolute <= 30)
  .map(item => item.keyword_data.keyword.toLowerCase());

let gapAnalysis = [];
let totaalGemisteWaarde = 0;

// 2. Vergelijk de Markt met de Prospect
marktData.forEach(item => {
  if (!item.keyword) return; 

  const kw = item.keyword.toLowerCase();
  // LET OP: search_volume en cpc zitten bij deze API in keyword_info
  const vol = item.keyword_info?.search_volume || 0;
  const cpc = item.keyword_info?.cpc || 0;

  // Controleer of ze NIET in de top 30 staan én we dit woord niet al hebben geteld
  if (!prospectKeywords.includes(kw) && !gapAnalysis.some(g => g.keyword === kw)) {
    // Berekening: Volume * 30% CTR (schatting nr 1 positie) * CPC * 12 maanden
    const jaarwaarde = (vol * 0.30 * cpc * 12);

    if (jaarwaarde > 0) {
        gapAnalysis.push({
          keyword: kw,
          jaarwaarde: Math.round(jaarwaarde),
          volume: vol,
          cpc: cpc
        });
        totaalGemisteWaarde += jaarwaarde;
    }
  }
});

// 3. Return de data voor het definitieve rapport
return {
  totaal_gemiste_waarde_jaar: Math.round(totaalGemisteWaarde),
  aantal_gaps: gapAnalysis.length,
  top_5_gaps: gapAnalysis.sort((a, b) => b.jaarwaarde - a.jaarwaarde).slice(0, 5)
};

// Pak de data van de directe vorige node (werkt altijd)
const data = $input.first().json;

const industry = data.industry || "growth hacking agency";
const brandName = data.brand_name;
const outputItems = [];

for (let i = 1; i <= 25; i++) {
  let prompt = `Geef een top 20 van de beste en meest toonaangevende ${industry} in Nederland. Geef uitsluitend een genummerde lijst met bedrijfsnamen. Geef absoluut geen introductie, geen uitleg en geen afsluiting. Alleen de namen. [Search Iteration: ${i}]`;

  outputItems.push({
    json: {
      iteratie: i,
      industry_target: industry,
      target_brand: brandName,
      ai_prompt: prompt
    }
  });
}

return outputItems;

const items = $input.all();

// 1. Brand name ophalen via node-referentie
const rawBrandName = $('Data extraheren').first().json.brand_name;
const displayBrandName = (rawBrandName && rawBrandName.length > 0) ? rawBrandName : "Onbekend";
const brandName = displayBrandName.toLowerCase().trim();

const searchTerms = [brandName];
if (brandName.indexOf('&') > -1) searchTerms.push(brandName.replace(/&/g, 'and'));
if (brandName.indexOf('and') > -1) searchTerms.push(brandName.replace(/and/g, '&'));

// 2. AI outputs verzamelen
var aiResponses = [];

for (var i = 0; i < items.length; i++) {
  var item = items[i];
  if (item.json && item.json.data && Array.isArray(item.json.data)) {
    for (var j = 0; j < item.json.data.length; j++) {
      var d = item.json.data[j];
      if (d.output) {
        aiResponses.push(d.output);
      }
    }
  }
}

// 3. Metrics berekenen
var visibilityCount = 0;
var totalRank = 0;
var top3Count = 0;
var highestRank = 999;
var lowestRank = 0;
var competitorTally = {};
var totalItems = aiResponses.length;

for (var r = 0; r < aiResponses.length; r++) {
  var lines = aiResponses[r].split('\n');
  var targetFoundInThisList = false;

  for (var l = 0; l < lines.length; l++) {
    var lowerLine = lines[l].toLowerCase();
    var match = lowerLine.match(/^\s*(\d+)[.)]\s*(.+)/);

    if (match) {
      var rank = parseInt(match[1], 10);
      var companyFound = match[2].replace(/[*_]/g, '').trim();
      var shortName = companyFound.split('-')[0].split(',')[0].trim();

      if (shortName.length > 2) {
        if (!competitorTally[shortName]) {
          competitorTally[shortName] = { mentions: 0, highestRank: 999 };
        }
        competitorTally[shortName].mentions = competitorTally[shortName].mentions + 1;
        if (rank < competitorTally[shortName].highestRank) {
          competitorTally[shortName].highestRank = rank;
        }
      }

      var isTarget = false;
      for (var t = 0; t < searchTerms.length; t++) {
        if (lowerLine.indexOf(searchTerms[t]) > -1) {
          isTarget = true;
          break;
        }
      }

      if (isTarget && !targetFoundInThisList) {
        targetFoundInThisList = true;
        visibilityCount = visibilityCount + 1;
        totalRank = totalRank + rank;
        if (rank <= 3) top3Count = top3Count + 1;
        if (rank < highestRank) highestRank = rank;
        if (rank > lowestRank) lowestRank = rank;
      }
    }
  }
}

// 4. Berekeningen
var visibilityPercentage = totalItems > 0 ? Math.round((visibilityCount / totalItems) * 100) : 0;
var averageRank = visibilityCount > 0 ? (totalRank / visibilityCount).toFixed(1) : "N.v.t.";

var competitorNames = Object.keys(competitorTally);
var sortedCompetitors = [];

for (var c = 0; c < competitorNames.length; c++) {
  var name = competitorNames[c];
  var nameLower = name.toLowerCase();
  var isProspect = false;
  for (var s = 0; s < searchTerms.length; s++) {
    if (nameLower.indexOf(searchTerms[s]) > -1) {
      isProspect = true;
      break;
    }
  }
  if (!isProspect) {
    sortedCompetitors.push({
      name: name,
      mentions: competitorTally[name].mentions,
      highestRank: competitorTally[name].highestRank
    });
  }
}

sortedCompetitors.sort(function(a, b) { return b.mentions - a.mentions; });

var top3Competitors = sortedCompetitors.slice(0, 3);
var uniqueCompetitorsCount = sortedCompetitors.length;

var prospectPiek = highestRank === 999 ? '-' : highestRank;
var concurrentNaam = top3Competitors.length > 0 ? top3Competitors[0].name : 'een andere speler';
var concurrentZichtbaarheid = top3Competitors.length > 0 ? Math.round((top3Competitors[0].mentions / totalItems) * 100) : 0;
var concurrentPiek = top3Competitors.length > 0 ? top3Competitors[0].highestRank : '-';

var concurrent1 = "N/A";
if (top3Competitors.length > 0) {
  concurrent1 = top3Competitors[0].name + ' (' + concurrentZichtbaarheid + '% zichtbaar, piekpositie: ' + top3Competitors[0].highestRank + ')';
}

var concurrent2 = "N/A";
if (top3Competitors.length > 1) {
  concurrent2 = top3Competitors[1].name + ' (' + Math.round((top3Competitors[1].mentions / totalItems) * 100) + '% zichtbaar, piekpositie: ' + top3Competitors[1].highestRank + ')';
}

var pitchZin = 'Jullie worden in ' + visibilityPercentage + '% van de AI-vragen genoemd, met een piek op positie ' + prospectPiek + '. Echter, jullie grootste concurrent, ' + concurrentNaam + ', domineert de AI-aanbevelingen in ' + concurrentZichtbaarheid + '% van de gevallen met een piek op positie ' + concurrentPiek + '. Tijd voor actie.';

return {
  bedrijfsnaam: displayBrandName,
  aantal_prompts: totalItems,
  zichtbaarheid_percentage: visibilityPercentage + '%',
  keer_in_top_3: top3Count,
  gemiddelde_positie_wanneer_zichtbaar: averageRank,
  hoogste_positie: highestRank === 999 ? "Geen" : highestRank,
  laagste_positie: lowestRank === 0 ? "Geen" : lowestRank,
  aantal_unieke_bedrijven_gevonden: uniqueCompetitorsCount,
  grootste_concurrent_1: concurrent1,
  grootste_concurrent_2: concurrent2,
  pitch_zin: pitchZin
};

