// Guard: if someone leaves the placeholder in, or passes an empty/invalid
// value, fall back to the embedded logo so the report never breaks.
function resolveLogo(candidate) {
  const value = typeof candidate === "string" ? candidate.trim() : "";
  const isValidSvg = value.startsWith("<svg") && value.includes("</svg>");
  return isValidSvg ? value : SS_LOGO_SVG;
}

const logoSvg = resolveLogo(SS_LOGO_SVG);

// ---------- Helpers ----------
function escapeHtml(value) {
  if (value === null || value === undefined) return "";
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function normalizeArray(value, fallback = []) {
  return Array.isArray(value) ? value.filter(Boolean) : fallback;
}

function limitWords(text, maxWords = 14) {
  if (!text) return "";
  const words = String(text).trim().split(/\s+/);
  if (words.length <= maxWords) return String(text);
  return words.slice(0, maxWords).join(" ") + "...";
}

function safeJsonParse(raw) {
  if (!raw) return null;

  let text = "";

  if (typeof raw === "string") {
    text = raw;
  } else if (raw.output) {
    text = typeof raw.output === "string" ? raw.output : JSON.stringify(raw.output);
  } else if (raw.content && Array.isArray(raw.content) && raw.content[0]?.text) {
    text = raw.content[0].text;
  } else {
    text = JSON.stringify(raw);
  }

  text = text
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");

  if (firstBrace !== -1 && lastBrace !== -1) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  return JSON.parse(text);
}

function scoreColor(score) {
  const value = Number(score) || 0;
  if (value >= 85) return "#A6FF00";
  if (value >= 65) return "#B2FA63";
  if (value >= 45) return "#FFB84D";
  return "#FF4D4D";
}

function scorePercent(score) {
  return Math.max(0, Math.min(100, Number(score) || 0));
}

// ---------- Parse input ----------
const input = $input.first().json;
const rawOutput = input.output || input.content || input;
const data = safeJsonParse(rawOutput);

if (!data) {
  throw new Error("No valid Growth Scan JSON found.");
}

// ---------- Data defaults ----------
const scan = {
  brand_name: data.brand_name || "Unknown Brand",
  industry: data.industry || "",
  business_model: data.business_model || "",
  primary_audience: data.primary_audience || "",
  conversion_goal: data.conversion_goal || "",
  kicker: data.kicker || "GROWTH SCAN",
  headline: data.headline || "From market tension to measurable growth.",
  intro: data.intro || "The market shows clear growth potential, but the current system is not capturing enough demand.",

  snapshot: {
    impact: data.snapshot?.impact || "Medium",
    growth_score: data.snapshot?.growth_score || "7.5",
    risk: data.snapshot?.risk || "Watch",
    commercial_value: data.snapshot?.commercial_value || "Medium"
  },

  snapshot_scores: {
    impact_score: data.snapshot_scores?.impact_score ?? 70,
    growth_potential_score: data.snapshot_scores?.growth_potential_score ?? 70,
    risk_score: data.snapshot_scores?.risk_score ?? 55,
    commercial_value_score: data.snapshot_scores?.commercial_value_score ?? 70
  },

  key_metrics: normalizeArray(data.key_metrics, []),
  market_research: data.market_research || {},
  seo_block: data.seo_block || {},
  geo_block: data.geo_block || {},
