function metricCard(label, value, score) {
  const percent = scorePercent(score);
  const color = scoreColor(score);

  return `
    <div class="metric-card">
      <div class="metric-ring" style="background: conic-gradient(${color} ${percent}%, rgba(255,255,255,0.12) 0);">
        <div class="metric-ring-inner"></div>
      </div>
      <div class="metric-copy">
        <div class="metric-value" style="color:${color};">${escapeHtml(value)}</div>
        <div class="metric-label">${escapeHtml(label)}</div>
      </div>
    </div>
  `;
}

function keyMetricGrid(metrics) {
  const safeMetrics = normalizeArray(metrics).slice(0, 4);
  if (!safeMetrics.length) return "";

  return `
    <section class="key-metric-grid">
      ${safeMetrics.map(metric => `
        <div class="key-metric-card">
          <div class="key-metric-value">${escapeHtml(metric.value)}</div>
          <div class="key-metric-label">${escapeHtml(metric.label)}</div>
          <div class="key-metric-context">${escapeHtml(metric.context)}</div>
        </div>
      `).join("")}
    </section>
  `;
}

function marketResearchBlock(marketResearch) {
  if (!marketResearch) return "";

  return `
    <section class="market-research-block">
      <div class="market-research-header">
        <h3>${escapeHtml(marketResearch.title || "Market Research Signals")}</h3>
