      <div class="scan-block-top">
        <h3>${escapeHtml(title)}</h3>
        <span>${escapeHtml(status)}</span>
      </div>
      <div class="scan-block-value">${escapeHtml(value)}</div>
      <div class="scan-block-label">${escapeHtml(label)}</div>
      <div class="scan-block-meta">
        ${normalizeArray(metaItems).map(item => `<div>${escapeHtml(item)}</div>`).join("")}
      </div>
      <p>${escapeHtml(limitWords(insight, 14))}</p>
    </section>
  `;
}

function aaaarrrFunnel(items) {
  const safeItems = normalizeArray(items).slice(0, 6);
  if (!safeItems.length) return "";

  return `
    <section class="funnel-card">
      <h3>Full Funnel Scan · Beyond Awareness</h3>
      <div class="funnel-grid">
        ${safeItems.map(item => {
          const score = scorePercent(item.score);
          const color = scoreColor(item.score);

          return `
            <div class="funnel-item">
              <div class="funnel-stage">${escapeHtml(item.stage)}</div>
              <div class="funnel-score" style="color:${color};">${score}</div>
              <div class="funnel-bar">
                <span style="width:${score}%; background:${color};"></span>
              </div>
              <div class="funnel-status">${escapeHtml(item.status)}</div>
              <p>${escapeHtml(limitWords(item.signal, 12))}</p>
            </div>
          `;
        }).join("")}
      </div>
    </section>
  `;
}

function panel(number, title, content, modifier = "") {
  return `
    <section class="dash-panel ${modifier}">
      <h3>${escapeHtml(number)}. ${escapeHtml(title)}</h3>
      ${content}
    </section>
  `;
}

function bulletList(items, maxWords = 10) {
  return `
    <ul class="dash-list">
      ${normalizeArray(items).slice(0, 3).map(item => `<li>${escapeHtml(limitWords(item, maxWords))}</li>`).join("")}
    </ul>
  `;
}

